#include "kernel_operator.h"
using namespace AscendC;

constexpr int32_t BUFFER_NUM = 2;

class KernelVanillaRnnHiddenCustom {
public:
    __aicore__ inline KernelVanillaRnnHiddenCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR h, GM_ADDR w_i2h, GM_ADDR b_i2h,
                                GM_ADDR w_h2o, GM_ADDR b_h2o,
                                GM_ADDR h_new, GM_ADDR y,
                                uint32_t B, uint32_t I, uint32_t H, uint32_t O, uint32_t K,
                                uint32_t batchPerBlock, uint32_t remainingBatch)
    {
        B_ = B; I_ = I; H_ = H; O_ = O; K_ = K;
        batchPerBlock_ = batchPerBlock;
        remainingBatch_ = remainingBatch;

        xGm_.SetGlobalBuffer((__gm__ float*)x, B * I);
        hGm_.SetGlobalBuffer((__gm__ float*)h, B * H);
        w_i2hGm_.SetGlobalBuffer((__gm__ float*)w_i2h, H * K);
        b_i2hGm_.SetGlobalBuffer((__gm__ float*)b_i2h, H);
        w_h2oGm_.SetGlobalBuffer((__gm__ float*)w_h2o, O * H);
        b_h2oGm_.SetGlobalBuffer((__gm__ float*)b_h2o, O);
        hNewGm_.SetGlobalBuffer((__gm__ float*)h_new, B * H);
        yGm_.SetGlobalBuffer((__gm__ float*)y, B * O);

        // Init local buffers for one batch element
        pipe_.InitBuffer(inpBuf_, 1, K_ * sizeof(float));
        pipe_.InitBuffer(preBuf_, 1, H_ * sizeof(float));
        pipe_.InitBuffer(ytBuf_, 1, O_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        uint32_t blockIdx = GetBlockIdx();
        uint32_t blockNum = GetBlockNum();
        // Determine batch range for this block
        uint32_t baseBatch = blockIdx * batchPerBlock_ + (blockIdx < remainingBatch_ ? blockIdx : remainingBatch_);
        uint32_t batchCnt = batchPerBlock_ + (blockIdx < remainingBatch_ ? 1 : 0);
        for (uint32_t b = 0; b < batchCnt; b++) {
            uint32_t batchIdx = baseBatch + b;
            ProcessOneBatch(batchIdx);
        }
    }

private:
    __aicore__ inline void ProcessOneBatch(uint32_t batchIdx)
    {
        // Load x_t (size I) and h (size H) from global
        LocalTensor<float> inp = inpBuf_.Get<float>();
        LocalTensor<float> pre = preBuf_.Get<float>();
        LocalTensor<float> yt = ytBuf_.Get<float>();

        // Copy x_t and h into inp (concatenated)
        DataCopy(inp, xGm_[batchIdx * I_], I_);
        DataCopy(inp[I_], hGm_[batchIdx * H_], H_);

        // pre = matmul(inp, w_i2h) + b_i2h
